#include<bits/stdc++.h>
using namespace std;
int a[150010];
int sum[410][410];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        for(int j=1;j<=388;j++)
        {
            sum[j][i%j]+=a[i];
        }
    }
    while(m--)
    {
        char op;
        int x,y;
        cin>>op;
        scanf("%d%d",&x,&y);
        if(op=='C')
        {
            for(int i=1;i<=388;i++)
            {
                sum[i][x%i]-=a[x];
            }
            a[x]=y;
            for(int i=1;i<=388;i++)
            {
                sum[i][x%i]+=a[x];
            }
        }
        else
        {
            if(x<=388)
            {
                printf("%d\n",sum[x][y]);
            }
            else
            {
                int ans=0;
                for(int i=y;i<=n;i+=x)
                {
                    ans+=a[i];
                }
                printf("%d\n",ans);
            }
        }
    }
    return 0;
}
